@startuml
package "Sistema_de_Cobranças" {

  class Cliente <<C>> {
    + id : Int #red;
    - nome : String #orange;
    * cobranças : List<Cobrança> #yellowgreen;

    fazerPagamento() #lightseagreen;
  }

  class Cobranca <<C>> {
    + id : Int #red;
    cliente : Client #gold;
    quitado : Boolean #darkgoldenrod;

    gerarBoleto() #mediumspringgreen;
    consultaBoleto():Boolean #limegreen; 
  }


  class Boleto<<C>>{
  	+id:Int#crimson;
	validade:Date#sandybrown;
	valor:Float#peru;	
}



interface GerarBoleto<<I>>{} 

interface PagarBaleto<<I>>{fazerPagamento()} 


Cliente --* Cobranca:"1..*"-->"0.."
PagarBaleto <|.. Cliente:dashed line
end package
@enduml
